const config = {
  "previewFeatures": [],
  "clientVersion": "7.5.0",
  "engineVersion": "280c870be64f457428992c43c1f6d557fab6e29e",
  "activeProvider": "postgresql",
  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\n// Get a free hosted Postgres database in seconds: `npx create-db`\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../src/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ─── Roles y permisos (RBAC en BD) ───\n\nmodel Role {\n  id          String      @id @default(cuid())\n  name        String\n  slug        String      @unique\n  description String?\n  isSystem    Boolean     @default(false)\n  createdAt   DateTime    @default(now())\n  updatedAt   DateTime    @updatedAt\n  authorities Authority[]\n  users       User[]\n}\n\nmodel Authority {\n  id         String @id @default(cuid())\n  roleId     String\n  permission String\n  role       Role   @relation(fields: [roleId], references: [id], onDelete: Cascade)\n\n  @@unique([roleId, permission])\n}\n\n// ─── Autenticación (múltiples métodos de login por usuario) ───\n\nmodel Account {\n  id           String   @id @default(cuid())\n  userId       String\n  provider     String // \"credentials\" | \"google\" | \"saml\" | etc.\n  providerId   String // username para credentials; sub/email para oauth\n  passwordHash String? // solo para provider \"credentials\"\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n  user         User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([provider, providerId])\n}\n\n// ─── Entidades principales ───\n\nmodel User {\n  id                         String                      @id @default(cuid())\n  name                       String\n  roleId                     String\n  role                       Role                        @relation(fields: [roleId], references: [id])\n  accounts                   Account[]\n  sessionVersion             Int                         @default(1)\n  phone                      String?\n  avatar                     String?\n  status                     String                      @default(\"activo\")\n  joinedAt                   DateTime                    @default(now())\n  lastActivity               DateTime?\n  createdAt                  DateTime                    @default(now())\n  updatedAt                  DateTime                    @updatedAt\n  contactsAssigned           Contact[]\n  opportunitiesAssigned      Opportunity[]\n  companiesAssigned          Company[]\n  activitiesAssigned         Activity[]\n  campaignsCreated           Campaign[]\n  crmFilesUploaded           CrmFile[]\n  crmSalesGoal               CrmUserSalesGoal?\n  crmUserMonthlySalesTargets CrmUserMonthlySalesTarget[]\n  aiConversations            AiConversation[]\n  aiKnowledgeBases           AiKnowledgeBase[]\n  activityLogs               ActivityLog[]\n  auditChangeSets            AuditChangeSet[]\n  crmNotifications           CrmNotification[]\n}\n\n/**\n * Alertas in-app por usuario (contacto nuevo, oportunidad ganada, tareas vencidas).\n */\nmodel CrmNotification {\n  id        String    @id @default(cuid())\n  userId    String\n  user      User      @relation(fields: [userId], references: [id], onDelete: Cascade)\n  /**\n   * contact_created | opportunity_won | task_overdue\n   */\n  kind      String\n  /**\n   * p. ej. overdue:activityId; evita duplicados por tarea vencida\n   */\n  dedupeKey String?\n  title     String\n  body      String    @db.Text\n  readAt    DateTime?\n  important Boolean   @default(false)\n  /**\n   * lead | exito | alerta | info — tipografía del listado\n   */\n  notifType String    @default(\"info\")\n  /**\n   * alta | media | baja\n   */\n  priority  String    @default(\"media\")\n  metadata  Json?\n  createdAt DateTime  @default(now())\n\n  @@unique([userId, dedupeKey])\n  @@index([userId, createdAt])\n}\n\n// ─── Registro de actividad (auditoría general, no diff por campo) ───\n\nmodel ActivityLog {\n  id          String   @id @default(cuid())\n  userId      String?\n  user        User?    @relation(fields: [userId], references: [id], onDelete: SetNull)\n  /**\n   * Nombre del usuario en el momento del evento\n   */\n  userName    String\n  action      String\n  module      String\n  entityType  String\n  entityId    String?\n  entityName  String?\n  description String   @db.Text\n  status      String   @default(\"exito\")\n  isCritical  Boolean  @default(false)\n  createdAt   DateTime @default(now())\n\n  @@index([userId])\n  @@index([module, createdAt])\n  @@index([entityType, entityId])\n  @@index([createdAt])\n}\n\n// ─── Auditoría detallada (cambios campo a campo, agrupados por operación) ───\n\nmodel AuditChangeSet {\n  id         String             @id @default(cuid())\n  userId     String?\n  user       User?              @relation(fields: [userId], references: [id], onDelete: SetNull)\n  userName   String\n  action     String\n  module     String\n  entityType String\n  entityId   String\n  entityName String?\n  createdAt  DateTime           @default(now())\n  entries    AuditChangeEntry[]\n\n  @@index([userId])\n  @@index([entityType, entityId])\n  @@index([module, createdAt])\n  @@index([createdAt])\n}\n\nmodel AuditChangeEntry {\n  id          String         @id @default(cuid())\n  changeSetId String\n  changeSet   AuditChangeSet @relation(fields: [changeSetId], references: [id], onDelete: Cascade)\n  fieldKey    String\n  fieldLabel  String\n  oldValue    String         @db.Text\n  newValue    String         @db.Text\n\n  @@index([changeSetId])\n}\n\n// ─── Asistente IA (varios hilos por usuario) ───\n\nmodel AiConversation {\n  id        String      @id @default(cuid())\n  userId    String\n  user      User        @relation(fields: [userId], references: [id], onDelete: Cascade)\n  /**\n   * Primer mensaje del usuario o \"Nuevo chat\".\n   */\n  title     String      @default(\"Nuevo chat\")\n  messages  AiMessage[]\n  createdAt DateTime    @default(now())\n  updatedAt DateTime    @updatedAt\n\n  @@index([userId, updatedAt])\n}\n\nmodel AiMessage {\n  id             String         @id @default(cuid())\n  conversationId String\n  conversation   AiConversation @relation(fields: [conversationId], references: [id], onDelete: Cascade)\n  /**\n   * user | assistant\n   */\n  role           String\n  content        String         @db.Text\n  /**\n   * links/actions para mensajes del asistente\n   */\n  meta           Json?\n  createdAt      DateTime       @default(now())\n\n  @@index([conversationId, createdAt])\n}\n\n// ─── Bases de conocimiento (RAG operativo por usuario) ───\n\nmodel AiKnowledgeBase {\n  id              String             @id @default(cuid())\n  userId          String\n  user            User               @relation(fields: [userId], references: [id], onDelete: Cascade)\n  title           String\n  /**\n   * documentos | web | faq | tabular (UI Agentes IA)\n   */\n  type            String             @default(\"documentos\")\n  /**\n   * text_only | upload | url | existing\n   */\n  sourceMode      String\n  /**\n   * Resumen / contenido pegado / notas (sin secretos de API)\n   */\n  description     String             @db.Text\n  chunkSize       Int                @default(400)\n  overlap         Int                @default(64)\n  linkedAgentId   String?\n  linkedAgentName String?\n  /**\n   * indexado | sync | error | pendiente\n   */\n  status          String             @default(\"pendiente\")\n  chunkCount      Int                @default(0)\n  /**\n   * Config estructurada (endpoint, método, ámbito CRM…); nunca guardar Bearer/API key en claro\n   */\n  sourceJson      Json?\n  indexError      String?            @db.Text\n  indexedAt       DateTime?\n  createdAt       DateTime           @default(now())\n  updatedAt       DateTime           @updatedAt\n  chunks          AiKnowledgeChunk[]\n\n  @@index([userId])\n  @@index([userId, updatedAt])\n}\n\nmodel AiKnowledgeChunk {\n  id              String                       @id @default(cuid())\n  knowledgeBaseId String\n  knowledgeBase   AiKnowledgeBase              @relation(fields: [knowledgeBaseId], references: [id], onDelete: Cascade)\n  position        Int\n  content         String                       @db.Text\n  /// Embeddings pgvector (dimensión = migración SQL + OPENAI_EMBEDDING_DIMENSION). Rellenado por EmbeddingsService.\n  embedding       Unsupported(\"vector(1536)\")?\n  createdAt       DateTime                     @default(now())\n\n  @@index([knowledgeBaseId, position])\n}\n\n/**\n * Instrucciones editables del copiloto lateral (una fila, id = global).\n */\nmodel AiAssistantInstruction {\n  id                    String   @id\n  instructionsChatTools String   @db.Text\n  instructionsStream    String   @db.Text\n  updatedByUserId       String?\n  updatedAt             DateTime @updatedAt\n}\n\n// ─── Configuración CRM (singleton + catálogos + metas por usuario) ───\n\nmodel CrmOrganizationProfile {\n  id                  String                  @id @default(\"default\")\n  name                String                  @default(\"Taxi Monterrico\")\n  description         String                  @default(\"\")\n  contactEmail        String                  @default(\"\")\n  contactPhone        String                  @default(\"\")\n  address             String                  @default(\"\")\n  globalWeeklyGoal    Float                   @default(0)\n  updatedAt           DateTime                @updatedAt\n  monthlySalesTargets CrmMonthlySalesTarget[]\n}\n\n/**\n * Meta de facturación del equipo por mes calendario (UTC). Sin fila → meta 0 en reportes / dashboard.\n */\nmodel CrmMonthlySalesTarget {\n  id             String                 @id @default(cuid())\n  organizationId String                 @default(\"default\")\n  periodStart    DateTime               @db.Date\n  amount         Float                  @default(0)\n  createdAt      DateTime               @default(now())\n  updatedAt      DateTime               @updatedAt\n  organization   CrmOrganizationProfile @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n\n  @@unique([organizationId, periodStart])\n  @@index([organizationId, periodStart])\n}\n\nmodel CrmLeadSource {\n  id        String  @id @default(cuid())\n  slug      String  @unique\n  name      String\n  enabled   Boolean @default(true)\n  sortOrder Int     @default(0)\n}\n\n/**\n * Etapas del CRM (contactos, empresas, oportunidades): un solo catálogo por slug\n */\nmodel CrmStage {\n  id          String  @id @default(cuid())\n  slug        String  @unique\n  name        String\n  color       String  @default(\"#64748b\")\n  probability Int     @default(0)\n  enabled     Boolean @default(true)\n  sortOrder   Int     @default(0)\n  /**\n   * Sembradas iniciales: no eliminar del catálogo si hay registros con esa etapa\n   */\n  isSystem    Boolean @default(false)\n}\n\nmodel CrmPriority {\n  id          String  @id @default(cuid())\n  slug        String  @unique\n  name        String\n  color       String\n  description String  @default(\"\")\n  enabled     Boolean @default(true)\n  sortOrder   Int     @default(0)\n}\n\nmodel CrmActivityType {\n  id        String  @id @default(cuid())\n  slug      String  @unique\n  name      String\n  enabled   Boolean @default(true)\n  sortOrder Int     @default(0)\n}\n\nmodel CrmUserSalesGoal {\n  userId        String\n  weeklyTarget  Float  @default(0)\n  monthlyTarget Float  @default(0)\n  user          User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@id([userId])\n}\n\n/**\n * Meta de ventas del asesor por mes calendario (UTC). Mes sin fila → meta 0 en reportes / tarjeta mensual.\n */\nmodel CrmUserMonthlySalesTarget {\n  id          String   @id @default(cuid())\n  userId      String\n  periodStart DateTime @db.Date\n  amount      Float    @default(0)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n  user        User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, periodStart])\n  @@index([userId, periodStart])\n}\n\nmodel Contact {\n  id                String               @id @default(cuid())\n  /**\n   * Segmento de URL para /contactos/:slug (único; también se acepta :id cuid en API)\n   */\n  urlSlug           String               @unique\n  name              String\n  cargo             String?\n  telefono          String\n  correo            String\n  fuente            String\n  etapa             String               @default(\"lead\")\n  assignedTo        String?\n  estimatedValue    Float                @default(0)\n  docType           String?\n  docNumber         String?\n  departamento      String?\n  provincia         String?\n  distrito          String?\n  direccion         String?\n  clienteRecuperado String?\n  etapaHistory      Json?\n  createdAt         DateTime             @default(now())\n  updatedAt         DateTime             @updatedAt\n  user              User?                @relation(fields: [assignedTo], references: [id], onDelete: SetNull)\n  companies         CompanyContact[]\n  contacts          ContactContact[]     @relation(\"ContactLinks\")\n  linkedBy          ContactContact[]     @relation(\"LinkedContacts\")\n  opportunities     ContactOpportunity[]\n  activities        ContactActivity[]\n\n  @@index([assignedTo])\n  @@index([etapa])\n  @@index([assignedTo, etapa])\n}\n\nmodel Company {\n  id                  String               @id @default(cuid())\n  /**\n   * Segmento de URL para /empresas/:slug\n   */\n  urlSlug             String               @unique\n  name                String\n  razonSocial         String?\n  ruc                 String? // TODO: añadir @unique cuando se resuelvan RUC duplicados (ej: 20000000000)\n  telefono            String?\n  domain              String?\n  rubro               String?\n  tipo                String?\n  linkedin            String?\n  correo              String?\n  distrito            String?\n  provincia           String?\n  departamento        String?\n  direccion           String?\n  /**\n   * Facturación / ingreso estimado a nivel cuenta (sincronizado con contactos/oportunidades vinculadas)\n   */\n  facturacionEstimada Float                @default(0)\n  fuente              String?\n  clienteRecuperado   String?\n  etapa               String               @default(\"lead\")\n  assignedTo          String?\n  createdAt           DateTime             @default(now())\n  updatedAt           DateTime             @updatedAt\n  user                User?                @relation(fields: [assignedTo], references: [id], onDelete: SetNull)\n  contacts            CompanyContact[]\n  companies           CompanyCompany[]     @relation(\"CompanyLinks\")\n  linkedBy            CompanyCompany[]     @relation(\"LinkedCompanies\")\n  opportunities       CompanyOpportunity[]\n  activities          CompanyActivity[]\n  /**\n   * Registro CRM “Cliente”: se crea al alcanzar etapa cierre_ganado (1:1 con empresa).\n   */\n  clientRecord        Client?\n\n  @@index([assignedTo])\n  @@index([etapa])\n}\n\nmodel Client {\n  id        String   @id @default(cuid())\n  companyId String   @unique\n  company   Company  @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  /**\n   * activo | inactivo | potencial\n   */\n  status    String   @default(\"activo\")\n  notes     String?\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([companyId])\n}\n\nmodel Opportunity {\n  id                String                   @id @default(cuid())\n  urlSlug           String                   @unique\n  title             String\n  amount            Float\n  probability       Int                      @default(0)\n  etapa             String\n  status            String                   @default(\"abierta\")\n  /**\n   * baja | media | alta\n   */\n  priority          String                   @default(\"media\")\n  expectedCloseDate DateTime?\n  assignedTo        String?\n  createdAt         DateTime                 @default(now())\n  updatedAt         DateTime                 @updatedAt\n  user              User?                    @relation(fields: [assignedTo], references: [id], onDelete: SetNull)\n  contacts          ContactOpportunity[]\n  companies         CompanyOpportunity[]\n  opportunities     OpportunityOpportunity[] @relation(\"OpportunityLinks\")\n  linkedBy          OpportunityOpportunity[] @relation(\"LinkedOpportunities\")\n  activities        OpportunityActivity[]\n\n  @@index([assignedTo])\n  @@index([etapa])\n  @@index([status])\n  @@index([assignedTo, etapa])\n  @@index([expectedCloseDate])\n}\n\n// ─── Activity: puede vincularse a muchos Contact, Company, Opportunity ───\n\nmodel Activity {\n  id            String                @id @default(cuid())\n  type          String\n  /**\n   * Modalidad cuando type = tarea: llamada | reunion | correo | whatsapp\n   */\n  taskKind      String?\n  title         String\n  description   String\n  assignedTo    String\n  status        String                @default(\"pendiente\")\n  dueDate       DateTime\n  startDate     DateTime?\n  startTime     String?\n  completedAt   DateTime?\n  createdAt     DateTime              @default(now())\n  updatedAt     DateTime              @updatedAt\n  user          User                  @relation(fields: [assignedTo], references: [id])\n  contacts      ContactActivity[]\n  companies     CompanyActivity[]\n  opportunities OpportunityActivity[]\n\n  @@index([assignedTo])\n  @@index([dueDate])\n  @@index([status])\n  @@index([assignedTo, dueDate])\n}\n\n// ─── Tablas de unión entre entidades principales ───\n\nmodel CompanyContact {\n  id        String  @id @default(cuid())\n  companyId String\n  contactId String\n  isPrimary Boolean @default(false)\n  company   Company @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  contact   Contact @relation(fields: [contactId], references: [id], onDelete: Cascade)\n\n  @@unique([companyId, contactId])\n}\n\nmodel ContactContact {\n  id        String  @id @default(cuid())\n  contactId String\n  linkedId  String\n  contact   Contact @relation(\"ContactLinks\", fields: [contactId], references: [id], onDelete: Cascade)\n  linked    Contact @relation(\"LinkedContacts\", fields: [linkedId], references: [id], onDelete: Cascade)\n\n  @@unique([contactId, linkedId])\n}\n\nmodel ContactOpportunity {\n  id            String      @id @default(cuid())\n  contactId     String\n  opportunityId String\n  contact       Contact     @relation(fields: [contactId], references: [id], onDelete: Cascade)\n  opportunity   Opportunity @relation(fields: [opportunityId], references: [id], onDelete: Cascade)\n\n  @@unique([contactId, opportunityId])\n}\n\nmodel CompanyCompany {\n  id        String  @id @default(cuid())\n  companyId String\n  linkedId  String\n  company   Company @relation(\"CompanyLinks\", fields: [companyId], references: [id], onDelete: Cascade)\n  linked    Company @relation(\"LinkedCompanies\", fields: [linkedId], references: [id], onDelete: Cascade)\n\n  @@unique([companyId, linkedId])\n}\n\nmodel CompanyOpportunity {\n  id            String      @id @default(cuid())\n  companyId     String\n  opportunityId String\n  company       Company     @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  opportunity   Opportunity @relation(fields: [opportunityId], references: [id], onDelete: Cascade)\n\n  @@unique([companyId, opportunityId])\n}\n\nmodel OpportunityOpportunity {\n  id            String      @id @default(cuid())\n  opportunityId String\n  linkedId      String\n  opportunity   Opportunity @relation(\"OpportunityLinks\", fields: [opportunityId], references: [id], onDelete: Cascade)\n  linked        Opportunity @relation(\"LinkedOpportunities\", fields: [linkedId], references: [id], onDelete: Cascade)\n\n  @@unique([opportunityId, linkedId])\n}\n\n// ─── Tablas de unión de Activity con Contact, Company, Opportunity ───\n\nmodel ContactActivity {\n  id         String   @id @default(cuid())\n  contactId  String\n  activityId String\n  contact    Contact  @relation(fields: [contactId], references: [id], onDelete: Cascade)\n  activity   Activity @relation(fields: [activityId], references: [id], onDelete: Cascade)\n\n  @@unique([contactId, activityId])\n}\n\nmodel CompanyActivity {\n  id         String   @id @default(cuid())\n  companyId  String\n  activityId String\n  company    Company  @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  activity   Activity @relation(fields: [activityId], references: [id], onDelete: Cascade)\n\n  @@unique([companyId, activityId])\n}\n\nmodel OpportunityActivity {\n  id            String      @id @default(cuid())\n  opportunityId String\n  activityId    String\n  opportunity   Opportunity @relation(fields: [opportunityId], references: [id], onDelete: Cascade)\n  activity      Activity    @relation(fields: [activityId], references: [id], onDelete: Cascade)\n\n  @@unique([opportunityId, activityId])\n}\n\n// Envíos de campaña por SMTP: historial para límite anti-spam por destinatario / hora\nmodel CampaignEmailSendLog {\n  id      String   @id @default(cuid())\n  toEmail String\n  sentAt  DateTime @default(now())\n\n  @@index([toEmail, sentAt])\n}\n\n// Campaña de mensajería masiva persistida (CRM)\nmodel Campaign {\n  id                String    @id @default(cuid())\n  name              String\n  status            String\n  channel           String\n  /**\n   * Contenido completo solo en borrador; en `sent` suele ser mínimo o null\n   */\n  messageJson       Json?\n  recipientsJson    Json?\n  /**\n   * Asunto guardado para campañas enviadas (sin cuerpo en BD)\n   */\n  subjectSnapshot   String?\n  resultsJson       Json?\n  recipientCount    Int       @default(0)\n  sentCount         Int       @default(0)\n  deliveredCount    Int       @default(0)\n  openedCount       Int       @default(0)\n  clickedCount      Int       @default(0)\n  failedCount       Int       @default(0)\n  bounceCount       Int       @default(0)\n  relatedContactIds String[]  @default([])\n  createdAt         DateTime  @default(now())\n  sentAt            DateTime?\n  createdById       String\n  createdByName     String\n  createdBy         User      @relation(fields: [createdById], references: [id], onDelete: Restrict)\n\n  @@index([createdById])\n  @@index([createdAt])\n}\n\n/**\n * Adjuntos del CRM: metadatos en BD; binario en S3/MinIO o URL pública (CDN) vía proxy de medios.\n */\nmodel CrmFile {\n  id                String   @id @default(cuid())\n  /**\n   * Clave S3 o URL https del CDN si la subida fue por MEDIA_UPLOAD_URL.\n   */\n  storageKey        String   @unique\n  originalName      String\n  mimeType          String\n  size              Int\n  /**\n   * contact | company | opportunity | activity | email | task\n   */\n  entityType        String\n  entityId          String\n  entityName        String?\n  relatedEntityType String?\n  relatedEntityId   String?\n  relatedEntityName String?\n  uploadedBy        String\n  createdAt         DateTime @default(now())\n  user              User     @relation(fields: [uploadedBy], references: [id], onDelete: Restrict)\n\n  @@index([entityType, entityId])\n  @@index([uploadedBy])\n  @@index([createdAt])\n}\n"
}

